import { RuleTester } from 'eslint';
import tseslint from 'typescript-eslint';
import { noConsole } from "../../rules/no-console.js";
import { languageOptions } from "../../runtime.js";
const ruleTester = new RuleTester({
    languageOptions: {
        ...languageOptions,
        parserOptions: {
            ecmaVersion: 'latest',
            sourceType: 'module',
            ecmaFeatures: {
                jsx: true,
            },
        },
    },
});
// Separate tester for TypeScript code
const tsRuleTester = new RuleTester({
    languageOptions: {
        ...languageOptions,
        parser: tseslint.parser,
        parserOptions: {
            ecmaVersion: 'latest',
            sourceType: 'module',
        },
    },
});
describe('no-console', () => {
    // Main test suite with JavaScript code
    ruleTester.run('no-console', noConsole, {
        valid: [
            {
                name: 'allows console methods on other objects',
                code: `
          const myConsole = { log: () => {}, error: () => {} };
          myConsole.log('msg');
          myConsole.error('error');
        `,
            },
            {
                name: 'allows locally shadowed console object',
                code: `
          const console = { log: () => {}, error: () => {} };
          console.log('test');
          console.error('error');
        `,
            },
            {
                name: 'allows SDK logger methods (recommended alternative)',
                code: `
          logger.debug('debug message');
          logger.info('info message');
          logger.warn('warning message');
          logger.error('error message');
        `,
            },
        ],
        invalid: [
            {
                name: 'reports errors for global console.log',
                code: `console.log('debug message');`,
                errors: [{ messageId: 'noConsole' }],
            },
            {
                name: 'reports errors for global console.info',
                code: `console.info('info message');`,
                errors: [{ messageId: 'noConsole' }],
            },
            {
                name: 'reports errors for global console.warn',
                code: `console.warn('warning message');`,
                errors: [{ messageId: 'noConsole' }],
            },
            {
                name: 'reports errors for global console.debug',
                code: `console.debug('debug message');`,
                errors: [{ messageId: 'noConsole' }],
            },
            {
                name: 'reports errors for global console.error',
                code: `console.error('error message');`,
                errors: [{ messageId: 'noConsole' }],
            },
            {
                name: 'reports errors for all console methods in one file',
                code: `
          console.log('log');
          console.info('info');
          console.warn('warn');
          console.debug('debug');
          console.error('error');
        `,
                errors: [
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                ],
            },
            {
                name: 'reports errors for window.console calls',
                code: `
          window.console.log('log');
          window.console.info('info');
          window.console.warn('warn');
          window.console.debug('debug');
          window.console.error('error');
        `,
                errors: [
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                ],
            },
            {
                name: 'reports errors for globalThis.console calls',
                code: `
          globalThis.console.log('log');
          globalThis.console.info('info');
          globalThis.console.warn('warn');
          globalThis.console.debug('debug');
          globalThis.console.error('error');
        `,
                errors: [
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                ],
            },
            {
                name: 'reports errors for self.console calls',
                code: `
          self.console.log('log');
          self.console.info('info');
          self.console.warn('warn');
          self.console.debug('debug');
          self.console.error('error');
        `,
                errors: [
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                ],
            },
            {
                name: 'reports errors for bracket notation console calls',
                code: `
          console['log']('log');
          console['info']('info');
          window.console['warn']('warn');
          globalThis.console['debug']('debug');
          self.console['error']('error');
        `,
                errors: [
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                ],
            },
            {
                name: 'reports error in React component with JSX',
                code: `
          import { Text } from '@hubspot/ui-extensions';
          function Component() {
            console.log('Debug info');
            console.error('Error occurred');
            return <Text>Hello</Text>;
          }
        `,
                errors: [{ messageId: 'noConsole' }, { messageId: 'noConsole' }],
            },
            {
                name: 'reports error in async, arrow, and class method contexts',
                code: `
          async function test1() { console.log('async'); }
          const test2 = () => console.warn('arrow');
          class Test { method() { console.error('class'); } }
        `,
                errors: [
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                ],
            },
            {
                name: 'reports error in try/catch and nested scopes',
                code: `
          try { console.error('error'); } catch (e) { console.warn('caught'); }
          function outer() { function inner() { console.debug('nested'); } }
        `,
                errors: [
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                    { messageId: 'noConsole' },
                ],
            },
        ],
    });
    // TypeScript-specific tests (requires TypeScript parser)
    tsRuleTester.run('no-console (TypeScript)', noConsole, {
        valid: [
            {
                name: 'allows console types in type alias',
                code: `
          type LogType = typeof console.log;
          type InfoType = typeof console.info;
          type WarnType = typeof console.warn;
          type DebugType = typeof console.debug;
          type ErrorType = typeof console.error;
        `,
            },
            {
                name: 'allows console types in interface property',
                code: `
          interface Logger {
            log: typeof console.log;
            info: typeof console.info;
            warn: typeof console.warn;
            debug: typeof console.debug;
            error: typeof console.error;
          }
        `,
            },
            {
                name: 'allows console types in function return type',
                code: `
          function getLogFn(): typeof console.log {
            return logger.debug;
          }

          function getErrorFn(): typeof console.error {
            return logger.error;
          }
        `,
            },
        ],
        invalid: [
            {
                name: 'reports error for console calls even after type declarations',
                code: `
          type LogType = typeof console.log;
          type ErrorType = typeof console.error;

          function getData() {
            console.log('Logging');
            console.error('Error');
          }
        `,
                errors: [{ messageId: 'noConsole' }, { messageId: 'noConsole' }],
            },
        ],
    });
});
